/**
 * Viewport State Slice
 *
 * External store for camera/viewport state using @zazcart/tools.
 * Solves the "stale closure" problem in animation loops by using
 * useSyncExternalStore instead of React useState.
 *
 * Benefits:
 * - State reads are synchronous (no batching delay)
 * - Animation loops always see current values
 * - No more cameraPosRef workaround needed
 *
 * @see TECH-DEBT-001
 * @see CLAUDE.md "React Hooks vs External Stores"
 */

import { createSyncSlice } from '@zazcart/tools';
import type { LODLevel } from '../data/types';

// ─────────────────────────────────────────────────────────────
// STATE TYPES
// ─────────────────────────────────────────────────────────────

export interface CameraPosition {
  x: number;
  y: number;
}

export interface MomentumState {
  velocityX: number;
  velocityY: number;
  isActive: boolean;
}

export interface AnimationState {
  isAnimating: boolean;
  startTime: number;
  duration: number;
  startX: number;
  startY: number;
  startZoom: number;
  targetX: number;
  targetY: number;
  targetZoom: number;
}

export interface CanvasSize {
  width: number;
  height: number;
}

export interface ViewportSliceState {
  // Camera position in world coordinates
  camera: CameraPosition;

  // Canvas dimensions (from R3F)
  canvasSize: CanvasSize;

  // Initialization flag
  isInitialized: boolean;

  // Momentum for inertial panning
  momentum: MomentumState;

  // Smooth animation state
  animation: AnimationState;

  // Interaction state
  isPanning: boolean;
  panStart: CameraPosition;
  cameraPosAtPanStart: CameraPosition;
}

// ─────────────────────────────────────────────────────────────
// INITIAL STATE
// ─────────────────────────────────────────────────────────────

const initialState: ViewportSliceState = {
  camera: { x: 0, y: 0 },
  canvasSize: { width: 800, height: 600 },
  isInitialized: false,
  momentum: {
    velocityX: 0,
    velocityY: 0,
    isActive: false,
  },
  animation: {
    isAnimating: false,
    startTime: 0,
    duration: 250,
    startX: 0,
    startY: 0,
    startZoom: 1,
    targetX: 0,
    targetY: 0,
    targetZoom: 1,
  },
  isPanning: false,
  panStart: { x: 0, y: 0 },
  cameraPosAtPanStart: { x: 0, y: 0 },
};

// ─────────────────────────────────────────────────────────────
// VIEWPORT SLICE
// ─────────────────────────────────────────────────────────────

export const viewportSlice = createSyncSlice({
  id: 'viewport',
  initial: initialState,
  cache: { policy: 'session' },  // Session-scoped: resets when app closes
  reducers: {
    // Camera position
    setCamera(state: ViewportSliceState, payload: CameraPosition) {
      state.camera = payload;
    },

    setCameraX(state: ViewportSliceState, payload: number) {
      state.camera.x = payload;
    },

    setCameraY(state: ViewportSliceState, payload: number) {
      state.camera.y = payload;
    },

    // Canvas size
    setCanvasSize(state: ViewportSliceState, payload: CanvasSize) {
      state.canvasSize = payload;
    },

    // Initialization
    initialize(
      state: ViewportSliceState,
      payload: { camera: CameraPosition; canvasSize: CanvasSize }
    ) {
      state.camera = payload.camera;
      state.canvasSize = payload.canvasSize;
      state.isInitialized = true;
    },

    // Momentum
    setMomentum(state: ViewportSliceState, payload: MomentumState) {
      state.momentum = payload;
    },

    startMomentum(
      state: ViewportSliceState,
      payload: { velocityX: number; velocityY: number }
    ) {
      state.momentum = {
        velocityX: payload.velocityX,
        velocityY: payload.velocityY,
        isActive: true,
      };
    },

    updateMomentum(
      state: ViewportSliceState,
      payload: { velocityX: number; velocityY: number; camera: CameraPosition }
    ) {
      state.momentum.velocityX = payload.velocityX;
      state.momentum.velocityY = payload.velocityY;
      state.camera = payload.camera;
    },

    stopMomentum(state: ViewportSliceState) {
      state.momentum = {
        velocityX: 0,
        velocityY: 0,
        isActive: false,
      };
    },

    // Animation
    startAnimation(
      state: ViewportSliceState,
      payload: {
        startX: number;
        startY: number;
        startZoom: number;
        targetX: number;
        targetY: number;
        targetZoom: number;
        duration?: number;
      }
    ) {
      state.animation = {
        isAnimating: true,
        startTime: Date.now(),
        duration: payload.duration ?? 250,
        startX: payload.startX,
        startY: payload.startY,
        startZoom: payload.startZoom,
        targetX: payload.targetX,
        targetY: payload.targetY,
        targetZoom: payload.targetZoom,
      };
    },

    updateAnimation(
      state: ViewportSliceState,
      payload: { camera: CameraPosition }
    ) {
      state.camera = payload.camera;
    },

    stopAnimation(state: ViewportSliceState) {
      state.animation.isAnimating = false;
    },

    // Panning
    startPan(
      state: ViewportSliceState,
      payload: { panStart: CameraPosition; cameraPosAtPanStart: CameraPosition }
    ) {
      state.isPanning = true;
      state.panStart = payload.panStart;
      state.cameraPosAtPanStart = payload.cameraPosAtPanStart;
    },

    updatePan(state: ViewportSliceState, payload: { camera: CameraPosition }) {
      state.camera = payload.camera;
    },

    endPan(state: ViewportSliceState) {
      state.isPanning = false;
    },

    // Reset
    reset() {
      return initialState;
    },
  },
});

export type ViewportSlice = typeof viewportSlice;

/**
 * EntityStore - STATE-ARCH-001 Phase 1 & 3
 *
 * High-performance TypedArray-based entity storage.
 * Uses Structure of Arrays (SoA) pattern for optimal cache utilization.
 *
 * Phase 1: EntityStore class with TypedArrays
 * Phase 3: React hooks for UI integration
 *
 * @module entity-store
 */

// Types
export type {
  TaskArrays,
  TaskStringData,
  IEntityStore,
  TaskData,
  TaskCursor,
  TaskTypeValue,
  TaskColorValue,
} from './types';

// Constants
export {
  TASK_TYPE,
  TASK_COLOR,
  TASK_TYPE_TO_VALUE,
  VALUE_TO_TASK_TYPE,
  TASK_COLOR_TO_VALUE,
  VALUE_TO_TASK_COLOR,
} from './types';

// EntityStore class and singleton
export { EntityStore, getEntityStore, resetEntityStore } from './EntityStore';

// React hooks (Phase 3: UI State Bridge)
export type { UseEntityStoreResult } from './useEntityStore';
export { useEntityStore, useEntityArrays, useTask } from './useEntityStore';

/**
 * EntityStore Types - STATE-ARCH-001 Phase 1
 *
 * Type definitions for the high-performance TypedArray-based entity store.
 * Uses Structure of Arrays (SoA) pattern for cache-friendly data access.
 *
 * Key principles:
 * - TypedArrays for numeric data (cache-friendly, no GC pressure)
 * - String IDs stored separately in Map<index, string>
 * - Direct mutation (no Proxy, no reactive wrappers)
 * - Zero allocations in hot path
 */

/**
 * Task type enum values for TypedArray storage
 * Stored as Uint8 (0-2)
 */
export const TASK_TYPE = {
  MAINTENANCE: 0,
  OVERHAUL: 1,
  INSPECTION: 2,
} as const;

export type TaskTypeValue = (typeof TASK_TYPE)[keyof typeof TASK_TYPE];

/**
 * Task color enum values for TypedArray storage
 * Stored as Uint8 (0-2)
 */
export const TASK_COLOR = {
  BLUE: 0,
  ORANGE: 1,
  GRAY: 2,
} as const;

export type TaskColorValue = (typeof TASK_COLOR)[keyof typeof TASK_COLOR];

/**
 * Map from string TaskType to numeric value
 */
export const TASK_TYPE_TO_VALUE: Record<string, TaskTypeValue> = {
  maintenance: TASK_TYPE.MAINTENANCE,
  overhaul: TASK_TYPE.OVERHAUL,
  inspection: TASK_TYPE.INSPECTION,
};

/**
 * Map from numeric value to string TaskType
 */
export const VALUE_TO_TASK_TYPE: Record<TaskTypeValue, string> = {
  [TASK_TYPE.MAINTENANCE]: 'maintenance',
  [TASK_TYPE.OVERHAUL]: 'overhaul',
  [TASK_TYPE.INSPECTION]: 'inspection',
};

/**
 * Map from string TaskColor to numeric value
 */
export const TASK_COLOR_TO_VALUE: Record<string, TaskColorValue> = {
  blue: TASK_COLOR.BLUE,
  orange: TASK_COLOR.ORANGE,
  gray: TASK_COLOR.GRAY,
};

/**
 * Map from numeric value to string TaskColor
 */
export const VALUE_TO_TASK_COLOR: Record<TaskColorValue, string> = {
  [TASK_COLOR.BLUE]: 'blue',
  [TASK_COLOR.ORANGE]: 'orange',
  [TASK_COLOR.GRAY]: 'gray',
};

/**
 * TypedArray storage for task entities
 * Structure of Arrays (SoA) pattern for optimal cache utilization
 *
 * Memory layout for N tasks:
 * - startDay: Float32Array(N) - 4 bytes per task
 * - duration: Float32Array(N) - 4 bytes per task
 * - trainIndex: Uint16Array(N) - 2 bytes per task
 * - type: Uint8Array(N) - 1 byte per task
 * - color: Uint8Array(N) - 1 byte per task
 * - hasConflict: Uint8Array(N) - 1 byte per task (0 or 1)
 * - predecessorIndex: Int32Array(N) - 4 bytes per task (-1 = no predecessor)
 *
 * Total: 17 bytes per task = ~1.7MB for 100k tasks
 * Compare to ~50MB+ for object-based storage with same data
 */
export interface TaskArrays {
  /** Start day offset from dataset start date */
  startDay: Float32Array;
  /** Duration in days */
  duration: Float32Array;
  /** Train index (Y position) */
  trainIndex: Uint16Array;
  /** Task type (0=maintenance, 1=overhaul, 2=inspection) */
  type: Uint8Array;
  /** Task color (0=blue, 1=orange, 2=gray) */
  color: Uint8Array;
  /** Conflict flag (0=false, 1=true) */
  hasConflict: Uint8Array;
  /** Predecessor task index (-1 = no predecessor) */
  predecessorIndex: Int32Array;
}

/**
 * String data stored separately (cannot be in TypedArray)
 * Uses index as key for O(1) lookup
 */
export interface TaskStringData {
  /** Map from task index to task ID string */
  ids: Map<number, string>;
  /** Reverse lookup: task ID string to index */
  idToIndex: Map<string, number>;
}

/**
 * Entity store interface
 * Provides typed access to SoA data
 */
export interface IEntityStore {
  /** Current number of entities */
  readonly count: number;
  /** Maximum capacity */
  readonly capacity: number;
  /** TypedArray storage */
  readonly arrays: TaskArrays;
  /** String data storage */
  readonly strings: TaskStringData;

  /**
   * Load entities from array of task objects
   * Bulk load is optimized for initial data loading
   */
  load(tasks: TaskData[]): void;

  /**
   * Get task data by index (zero-allocation read)
   * Returns a cursor that reads directly from arrays
   */
  get(index: number): TaskCursor;

  /**
   * Get task data by ID
   * Returns null if not found
   */
  getById(id: string): TaskCursor | null;

  /**
   * Clear all entities
   */
  clear(): void;

  /**
   * Get iterator over all valid entities
   */
  [Symbol.iterator](): Iterator<TaskCursor>;
}

/**
 * Task data input format (from generator or API)
 */
export interface TaskData {
  id: string;
  trainIndex: number;
  startDay: number;
  duration: number;
  type: 'maintenance' | 'overhaul' | 'inspection';
  color: 'blue' | 'orange' | 'gray';
  hasConflict: boolean;
  predecessorId?: string;
}

/**
 * Task cursor - provides ergonomic read access to TypedArray data
 * This is a lightweight view into the arrays, not a copy
 *
 * IMPORTANT: Do not store cursor references - they are invalidated
 * when the underlying arrays are modified
 */
export interface TaskCursor {
  /** Entity index in the arrays */
  readonly index: number;
  /** Task ID string */
  readonly id: string;
  /** Start day offset */
  readonly startDay: number;
  /** Duration in days */
  readonly duration: number;
  /** Train index */
  readonly trainIndex: number;
  /** Task type as numeric value */
  readonly typeValue: TaskTypeValue;
  /** Task type as string */
  readonly type: string;
  /** Task color as numeric value */
  readonly colorValue: TaskColorValue;
  /** Task color as string */
  readonly color: string;
  /** Whether task has conflict */
  readonly hasConflict: boolean;
  /** Predecessor task index (-1 if none) */
  readonly predecessorIndex: number;
  /** Predecessor task ID (undefined if none) */
  readonly predecessorId: string | undefined;

  // Computed properties for rendering
  /** X position in world coordinates */
  readonly x: number;
  /** Y position in world coordinates */
  readonly y: number;
  /** Width in world coordinates */
  readonly width: number;
}

/**
 * Canvas State Machine
 *
 * Central state management for the MMS Canvas using @zazcart/tools.
 * Uses useSyncExternalStore for React integration without stale closure issues.
 *
 * Slices:
 * - viewport: Camera position, momentum, animation, panning
 * - interaction: Hover and selection state for tasks
 *
 * @see TECH-DEBT-001
 * @see F018 - Hover highlight
 * @see F019 - Click to select
 */

import { createMachine } from '@zazcart/tools';
import { viewportSlice } from './viewport';
import { interactionSlice } from './interaction';

// ─────────────────────────────────────────────────────────────
// CANVAS MACHINE
// ─────────────────────────────────────────────────────────────

export const canvasMachine = createMachine({
  id: 'canvas',
  slices: {
    viewport: viewportSlice,
    interaction: interactionSlice,
  },
  context: {
    userID: null,  // Canvas is public/anonymous, no user context needed
  },
  // Disable metadata tracking for high-frequency state updates (60fps)
  // This prevents GC thrashing from object allocations on every dispatch
  metadata: false,
});

// ─────────────────────────────────────────────────────────────
// EXPORTS
// ─────────────────────────────────────────────────────────────

// Typed hooks for React components
export const useCanvas = canvasMachine.useMachine;
export const useCanvasSelector = canvasMachine.useSelector;

// Actions for dispatching state changes
export const canvasActions = canvasMachine.actions;

// Direct store access for animation loops (no React re-render)
export const canvasStore = {
  getState: canvasMachine.getState,
  dispatch: canvasMachine.dispatch,
  subscribe: canvasMachine.subscribe,
};

// Re-export types
export type { ViewportSliceState, CameraPosition, MomentumState, AnimationState, CanvasSize } from './viewport';
export type { InteractionSliceState } from './interaction';

/**
 * Spatial Indexing Types for PERF-002
 *
 * This module defines interfaces for spatial queries on the canvas.
 * The goal is to efficiently find entities within a viewport region
 * without iterating through all 60k+ tasks.
 *
 * Architecture:
 * - ISpatialIndex: Abstract interface for any spatial index implementation
 * - SimpleSpatialIndex: O(n) placeholder (this PR)
 * - RBushSpatialIndex: Full R-tree implementation (STATE-ARCH-001.Phase2)
 *
 * Coordinate system matches canvas:
 * - X: days from start (positive = future)
 * - Y: train rows (0 = top, negative = down)
 */

import type { TaskRender } from '../data/types';

// ─────────────────────────────────────────────────────────────
// VIEWPORT BOUNDS
// ─────────────────────────────────────────────────────────────

/**
 * Rectangle defining the visible viewport in world coordinates.
 * Used for culling queries - only render entities within these bounds.
 */
export interface ViewportBounds {
  /** Left edge in world X (days * pxPerDay) */
  minX: number;
  /** Right edge in world X */
  maxX: number;
  /** Bottom edge in world Y (negative, more trains) */
  minY: number;
  /** Top edge in world Y (closer to 0) */
  maxY: number;
}

/**
 * Entity bounding box for spatial indexing.
 * Compatible with RBush item format.
 */
export interface SpatialItem {
  /** Left edge */
  minX: number;
  /** Right edge */
  maxX: number;
  /** Bottom edge (lower Y value, more negative) */
  minY: number;
  /** Top edge (higher Y value, closer to 0) */
  maxY: number;
  /** Reference to the entity ID */
  id: string;
}

// ─────────────────────────────────────────────────────────────
// SPATIAL INDEX INTERFACE
// ─────────────────────────────────────────────────────────────

/**
 * Query result with optional distance for nearest-neighbor queries.
 */
export interface SpatialQueryResult {
  /** Entity ID */
  id: string;
  /** Distance from query point (for nearest queries) */
  distance?: number;
}

/**
 * Statistics for monitoring index performance.
 */
export interface SpatialIndexStats {
  /** Total number of indexed items */
  itemCount: number;
  /** Time taken for last bulk load (ms) */
  lastBuildTimeMs?: number;
  /** Time taken for last query (ms) */
  lastQueryTimeMs?: number;
  /** Number of items returned in last query */
  lastQueryResultCount?: number;
}

/**
 * Abstract interface for spatial indexing.
 *
 * This interface is implementation-agnostic - it can be backed by:
 * - SimpleSpatialIndex: O(n) linear scan (placeholder)
 * - RBushSpatialIndex: R-tree for O(log n) queries
 * - FlatbushSpatialIndex: Static R-tree for read-heavy workloads
 * - Custom TypedArray-based index for maximum performance
 *
 * Usage pattern:
 * 1. Create index and load data once (or on data change)
 * 2. Query frequently during pan/zoom
 * 3. Clear and rebuild only when data changes
 */
export interface ISpatialIndex {
  /**
   * Bulk load items into the index.
   * More efficient than inserting one by one.
   *
   * @param items - Array of items to index
   */
  load(items: SpatialItem[]): void;

  /**
   * Insert a single item into the index.
   * Use sparingly - bulk load is more efficient.
   *
   * @param item - Item to insert
   */
  insert(item: SpatialItem): void;

  /**
   * Remove an item from the index by ID.
   *
   * @param id - ID of item to remove
   * @returns true if item was found and removed
   */
  remove(id: string): boolean;

  /**
   * Clear all items from the index.
   */
  clear(): void;

  /**
   * Query items within viewport bounds.
   * This is the main query used for viewport culling.
   *
   * @param bounds - Viewport rectangle in world coordinates
   * @returns Array of item IDs within bounds
   */
  queryViewport(bounds: ViewportBounds): string[];

  /**
   * Query items within a circular region.
   * Useful for mouse hover detection.
   *
   * @param x - Center X in world coordinates
   * @param y - Center Y in world coordinates
   * @param radius - Search radius in world units
   * @returns Array of item IDs within radius
   */
  queryRadius(x: number, y: number, radius: number): string[];

  /**
   * Find the nearest item to a point.
   * Useful for snapping and selection.
   *
   * @param x - Query X in world coordinates
   * @param y - Query Y in world coordinates
   * @param maxDistance - Maximum search distance (optional)
   * @returns Nearest item ID and distance, or null if none found
   */
  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null;

  /**
   * Get performance statistics.
   */
  getStats(): SpatialIndexStats;
}

// ─────────────────────────────────────────────────────────────
// HELPER FUNCTIONS
// ─────────────────────────────────────────────────────────────

/**
 * Convert a TaskRender to a SpatialItem for indexing.
 *
 * @param task - Task with render coordinates
 * @param pxPerDay - Pixels per day (default: 10)
 * @param pxPerTrain - Pixels per train row (default: 24)
 * @returns SpatialItem for indexing
 */
export function taskToSpatialItem(
  task: TaskRender,
  pxPerDay: number = 10,
  pxPerTrain: number = 24
): SpatialItem {
  const minX = task.startDay * pxPerDay;
  const maxX = (task.startDay + task.duration) * pxPerDay;
  // Y is negative (trains go downward from 0)
  const maxY = -task.trainIndex * pxPerTrain;
  const minY = maxY - pxPerTrain;

  return {
    minX,
    maxX,
    minY,
    maxY,
    id: task.id,
  };
}

/**
 * Convert an array of TaskRender to SpatialItems.
 *
 * @param tasks - Array of tasks
 * @param pxPerDay - Pixels per day
 * @param pxPerTrain - Pixels per train row
 * @returns Array of SpatialItems
 */
export function tasksToSpatialItems(
  tasks: TaskRender[],
  pxPerDay: number = 10,
  pxPerTrain: number = 24
): SpatialItem[] {
  return tasks.map(task => taskToSpatialItem(task, pxPerDay, pxPerTrain));
}

/**
 * Check if two rectangles intersect.
 *
 * @param a - First rectangle
 * @param b - Second rectangle
 * @returns true if rectangles overlap
 */
export function rectanglesIntersect(
  a: { minX: number; maxX: number; minY: number; maxY: number },
  b: { minX: number; maxX: number; minY: number; maxY: number }
): boolean {
  return a.minX <= b.maxX && a.maxX >= b.minX && a.minY <= b.maxY && a.maxY >= b.minY;
}

/**
 * Calculate distance from a point to the center of a rectangle.
 *
 * @param px - Point X
 * @param py - Point Y
 * @param rect - Rectangle
 * @returns Distance to center
 */
export function distanceToCenter(
  px: number,
  py: number,
  rect: { minX: number; maxX: number; minY: number; maxY: number }
): number {
  const cx = (rect.minX + rect.maxX) / 2;
  const cy = (rect.minY + rect.maxY) / 2;
  return Math.sqrt((px - cx) ** 2 + (py - cy) ** 2);
}

