/**
 * PerfMonitor - Performance monitoring component for WebGL/R3F applications
 *
 * Features:
 * - Real-time FPS, MS, Memory, GPU, Draw Calls, Triangles display via r3f-perf
 * - Detailed logging system with circular buffer (60s of metrics)
 * - Session recording for performance testing
 * - Global API exposed via window for programmatic access
 *
 * Usage:
 * - Visual: Press 'P' key or use toggle button to show/hide panel
 * - Console: window.__PERF_LOG__ - access log buffer
 * - Console: window.__PERF_EXPORT__() - export full log as array
 * - Console: window.__PERF_START_SESSION__('test') - start recording session
 * - Console: window.__PERF_STOP_SESSION__() - stop and get session stats
 *
 * @see docs/PERFORMANCE_LOGGING.md for detailed documentation
 */

import { useEffect, useRef, useCallback, useState } from 'react';
import { Perf, usePerf } from 'r3f-perf';

// ─────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────

/**
 * Event type for performance logging
 */
type PerfEvent = 'idle' | 'panning' | 'zooming' | 'animating' | 'lod_transition' | 'unknown';

/**
 * Single metric entry in the log buffer
 */
interface PerfLogEntry {
  timestamp: number;
  fps: {
    current: number;
    avg: number;
    min: number;
    max: number;
  };
  ms: {
    current: number;
    avg: number;
    max: number;
  };
  memory: number; // MB
  gpu: number | null; // GPU time in ms (may not be available)
  drawCalls: number;
  triangles: number;
  event: PerfEvent;
}

/**
 * Session statistics returned by __PERF_STOP_SESSION__
 */
interface PerfSessionStats {
  name: string;
  duration: number; // seconds
  totalFrames: number;
  fps: {
    avg: number;
    min: number;
    max: number;
    p1: number; // 1st percentile (worst 1%)
    p99: number; // 99th percentile (best 99%)
  };
  ms: {
    avg: number;
    max: number;
  };
  framesBelow30: number;
  framesBelow60: number;
  entries: PerfLogEntry[];
}

/**
 * Active session state
 */
interface PerfSession {
  name: string;
  startTime: number;
  entries: PerfLogEntry[];
  fpsValues: number[];
}

// ─────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────

const LOG_BUFFER_DURATION_MS = 60000; // 60 seconds of logs
const LOG_INTERVAL_FRAMES = 60; // Log every 60 frames (~1 second at 60fps)

// ─────────────────────────────────────────────────────────────
// GLOBAL STATE (accessible via window)
// ─────────────────────────────────────────────────────────────

// Circular buffer for performance logs
let perfLogBuffer: PerfLogEntry[] = [];
let currentSession: PerfSession | null = null;
let frameCounter = 0;
let fpsHistory: number[] = [];
let msHistory: number[] = [];

// Rolling statistics for averaging
const rollingWindow = 60; // frames for rolling average

/**
 * Clear old entries from buffer based on timestamp
 */
function pruneOldEntries() {
  const cutoff = Date.now() - LOG_BUFFER_DURATION_MS;
  perfLogBuffer = perfLogBuffer.filter((entry) => entry.timestamp > cutoff);
}

/**
 * Calculate percentile from sorted array
 */
function percentile(sortedArr: number[], p: number): number {
  if (sortedArr.length === 0) return 0;
  const index = Math.ceil((p / 100) * sortedArr.length) - 1;
  return sortedArr[Math.max(0, Math.min(index, sortedArr.length - 1))];
}

/**
 * Export the global performance API to window
 */
function setupGlobalAPI() {
  // Make log buffer accessible
  Object.defineProperty(window, '__PERF_LOG__', {
    get: () => [...perfLogBuffer],
    configurable: true,
  });

  // Export full log
  (window as any).__PERF_EXPORT__ = (): PerfLogEntry[] => {
    return [...perfLogBuffer];
  };

  // Start a named session
  (window as any).__PERF_START_SESSION__ = (name: string): void => {
    if (currentSession) {
      console.warn(`[PERF] Session "${currentSession.name}" already running. Stopping it first.`);
      (window as any).__PERF_STOP_SESSION__();
    }
    currentSession = {
      name,
      startTime: Date.now(),
      entries: [],
      fpsValues: [],
    };
    console.log(`[PERF] Session "${name}" started`);
  };

  // Stop current session and return stats
  (window as any).__PERF_STOP_SESSION__ = (): PerfSessionStats | null => {
    if (!currentSession) {
      console.warn('[PERF] No active session to stop');
      return null;
    }

    const session = currentSession;
    currentSession = null;

    const duration = (Date.now() - session.startTime) / 1000;
    const sortedFps = [...session.fpsValues].sort((a, b) => a - b);

    const stats: PerfSessionStats = {
      name: session.name,
      duration,
      totalFrames: session.fpsValues.length,
      fps: {
        avg: sortedFps.length > 0 ? sortedFps.reduce((a, b) => a + b, 0) / sortedFps.length : 0,
        min: sortedFps.length > 0 ? sortedFps[0] : 0,
        max: sortedFps.length > 0 ? sortedFps[sortedFps.length - 1] : 0,
        p1: percentile(sortedFps, 1),
        p99: percentile(sortedFps, 99),
      },
      ms: {
        avg: session.entries.length > 0
          ? session.entries.reduce((a, e) => a + e.ms.current, 0) / session.entries.length
          : 0,
        max: session.entries.length > 0
          ? Math.max(...session.entries.map((e) => e.ms.current))
          : 0,
      },
      framesBelow30: session.fpsValues.filter((fps) => fps < 30).length,
      framesBelow60: session.fpsValues.filter((fps) => fps < 60).length,
      entries: session.entries,
    };

    console.log(`[PERF] Session "${session.name}" stopped:`, {
      duration: `${duration.toFixed(2)}s`,
      avgFPS: stats.fps.avg.toFixed(1),
      p1FPS: stats.fps.p1.toFixed(1),
      p99FPS: stats.fps.p99.toFixed(1),
      framesBelow30: stats.framesBelow30,
      framesBelow60: stats.framesBelow60,
    });

    return stats;
  };

  // Get current session status
  (window as any).__PERF_SESSION_STATUS__ = (): { active: boolean; name?: string; duration?: number } => {
    if (!currentSession) {
      return { active: false };
    }
    return {
      active: true,
      name: currentSession.name,
      duration: (Date.now() - currentSession.startTime) / 1000,
    };
  };

  // Clear log buffer
  (window as any).__PERF_CLEAR__ = (): void => {
    perfLogBuffer = [];
    console.log('[PERF] Log buffer cleared');
  };
}

// ─────────────────────────────────────────────────────────────
// PERF LOGGER COMPONENT (runs inside R3F Canvas)
// ─────────────────────────────────────────────────────────────

/**
 * Internal component that reads r3f-perf data and logs it
 * Must be rendered inside R3F Canvas context
 */
function PerfLogger({ currentEvent }: { currentEvent: PerfEvent }) {
  const perfData = usePerf();

  useEffect(() => {
    if (!perfData) return;

    frameCounter++;

    // Track FPS for rolling average
    const currentFps = perfData.log?.fps ?? 0;
    const currentMs = perfData.log?.ms ?? 16.67;

    fpsHistory.push(currentFps);
    msHistory.push(currentMs);

    // Keep rolling window
    if (fpsHistory.length > rollingWindow) {
      fpsHistory.shift();
      msHistory.shift();
    }

    // Track for active session (every frame)
    if (currentSession) {
      currentSession.fpsValues.push(currentFps);
    }

    // Log every N frames
    if (frameCounter >= LOG_INTERVAL_FRAMES) {
      frameCounter = 0;

      // Calculate rolling stats
      const avgFps = fpsHistory.reduce((a, b) => a + b, 0) / fpsHistory.length;
      const minFps = Math.min(...fpsHistory);
      const maxFps = Math.max(...fpsHistory);
      const avgMs = msHistory.reduce((a, b) => a + b, 0) / msHistory.length;
      const maxMs = Math.max(...msHistory);

      const entry: PerfLogEntry = {
        timestamp: Date.now(),
        fps: {
          current: currentFps,
          avg: avgFps,
          min: minFps,
          max: maxFps,
        },
        ms: {
          current: currentMs,
          avg: avgMs,
          max: maxMs,
        },
        memory: perfData.log?.mem ?? 0,
        gpu: perfData.log?.gpu ?? null,
        drawCalls: perfData.log?.calls ?? 0,
        triangles: perfData.log?.triangles ?? 0,
        event: currentEvent,
      };

      // Add to buffer
      perfLogBuffer.push(entry);
      pruneOldEntries();

      // Add to active session
      if (currentSession) {
        currentSession.entries.push(entry);
      }
    }
  });

  return null;
}

// ─────────────────────────────────────────────────────────────
// MAIN PERF MONITOR COMPONENT
// ─────────────────────────────────────────────────────────────

interface PerfMonitorProps {
  /** Whether the perf panel is visible */
  visible?: boolean;
  /** Callback when visibility changes (for external control) */
  onVisibilityChange?: (visible: boolean) => void;
  /** Current event type for logging context */
  currentEvent?: PerfEvent;
  /** Position of the panel */
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
}

/**
 * Performance monitor component with r3f-perf panel and logging system
 *
 * This component should be rendered INSIDE the R3F Canvas.
 *
 * @example
 * <Canvas>
 *   <PerfMonitor visible={showPerf} />
 *   {... other scene content ...}
 * </Canvas>
 */
export function PerfMonitor({
  visible = true,
  currentEvent = 'idle',
  position = 'bottom-left', // BUG-006: Changed from top-right to avoid blocking navbar controls
}: PerfMonitorProps) {
  // Setup global API on mount
  useEffect(() => {
    setupGlobalAPI();
    console.log('[PERF] Performance monitor initialized. Available commands:');
    console.log('  window.__PERF_LOG__ - Access log buffer');
    console.log('  window.__PERF_EXPORT__() - Export full log');
    console.log('  window.__PERF_START_SESSION__(name) - Start recording');
    console.log('  window.__PERF_STOP_SESSION__() - Stop and get stats');
    console.log('  window.__PERF_CLEAR__() - Clear log buffer');

    return () => {
      // Cleanup (optional - keep API available for debugging)
    };
  }, []);

  return (
    <>
      {/* r3f-perf visual panel */}
      {visible && (
        <Perf
          position={position}
          minimal={false}
          showGraph={true}
          colorBlind={false}
          antialias={true}
          overClock={true}
          deepAnalyze={true}
          matrixUpdate={true}
        />
      )}

      {/* Logger that runs continuously (even when panel is hidden) */}
      <PerfLogger currentEvent={currentEvent} />
    </>
  );
}

/**
 * Hook to toggle perf monitor visibility with keyboard shortcut
 *
 * @example
 * const { visible, toggle } = usePerfMonitorToggle();
 */
export function usePerfMonitorToggle(initialVisible = false) {
  const [visible, setVisible] = useState(initialVisible);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Toggle on 'P' key (not when typing in input)
      if (
        e.key === 'p' &&
        !e.ctrlKey &&
        !e.metaKey &&
        !e.altKey &&
        !(e.target instanceof HTMLInputElement) &&
        !(e.target instanceof HTMLTextAreaElement)
      ) {
        setVisible((v) => !v);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const toggle = useCallback(() => setVisible((v) => !v), []);

  return { visible, toggle, setVisible };
}

// Export types for external use
export type { PerfEvent, PerfLogEntry, PerfSessionStats };

/**
 * TaskDetailsPanel Component (F026)
 *
 * Shows detailed task information in a side panel when a task is selected.
 * Uses BlueprintJS Drawer for the panel.
 *
 * Features:
 * - Opens when a task is selected
 * - Displays comprehensive task information
 * - Closes on deselect or close button click
 * - Shows conflict status with visual indicator
 */

import { useMemo, useCallback } from 'react';
import {
  Drawer,
  DrawerSize,
  Button,
  Tag,
  Intent,
  Icon,
  Divider,
  H4,
  H5,
  Classes,
} from '@blueprintjs/core';
import { getData } from '../data/generator';
import { useCanvasSelector, canvasStore, canvasActions } from '../state';
import type { TaskType, AssetType } from '../data/types';

// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

/**
 * Get intent color for task type
 */
function getTypeIntent(type: TaskType): Intent {
  switch (type) {
    case 'maintenance':
      return Intent.PRIMARY;
    case 'overhaul':
      return Intent.WARNING;
    case 'inspection':
      return Intent.NONE;
  }
}

/**
 * Get icon for task type
 */
function getTypeIcon(type: TaskType): string {
  switch (type) {
    case 'maintenance':
      return 'wrench';
    case 'overhaul':
      return 'build';
    case 'inspection':
      return 'eye-open';
  }
}

/**
 * Get icon for asset type (train fleet)
 */
function getAssetIcon(assetType: AssetType): string {
  return assetType === 'ALSTOM' ? 'train' : 'tram';
}

/**
 * Format date for display (e.g., "Mar 15, 2024")
 */
function formatDate(isoDate: string): string {
  const date = new Date(isoDate);
  return date.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

/**
 * Calculate duration in days from ISO dates
 */
function calculateDuration(startDate: string, endDate: string): number {
  const start = new Date(startDate);
  const end = new Date(endDate);
  const diffTime = end.getTime() - start.getTime();
  return Math.round(diffTime / (1000 * 60 * 60 * 24));
}

/**
 * Capitalize first letter
 */
function capitalize(str: string): string {
  return str.charAt(0).toUpperCase() + str.slice(1);
}

// ─────────────────────────────────────────────────────────────
// COMPONENT
// ─────────────────────────────────────────────────────────────

export function TaskDetailsPanel() {
  // Get selected task ID from canvas state
  const selectedTaskId = useCanvasSelector((s) => s.interaction.selectedTaskId);

  // Close handler - clears selection
  const handleClose = useCallback(() => {
    canvasStore.dispatch(canvasActions.interaction.clearSelection());
  }, []);

  // Get task details
  const taskData = useMemo(() => {
    if (!selectedTaskId) return null;

    const data = getData();
    const task = data.tasks.find((t) => t.id === selectedTaskId);
    if (!task) return null;

    const train = data.trains.find((t) => t.id === task.trainId);
    const duration = calculateDuration(task.startDate, task.endDate);

    // Find predecessor task if exists
    let predecessorTask = null;
    if (task.predecessorId) {
      predecessorTask = data.tasks.find((t) => t.id === task.predecessorId);
    }

    // Find successor tasks (tasks that depend on this one)
    const successorTasks = data.tasks.filter(
      (t) => t.predecessorId === task.id
    );

    return {
      id: task.id,
      trainId: task.trainId,
      trainName: train?.name || task.trainId,
      assetType: train?.assetType || 'ALSTOM',
      type: task.type,
      startDate: task.startDate,
      endDate: task.endDate,
      duration,
      hasConflict: task.hasConflict,
      predecessorId: task.predecessorId,
      predecessorTask,
      successorTasks,
    };
  }, [selectedTaskId]);

  // Render nothing if no task selected
  const isOpen = taskData !== null;

  return (
    <Drawer
      isOpen={isOpen}
      onClose={handleClose}
      size={DrawerSize.SMALL}
      title={
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <Icon icon="info-sign" />
          <span>Task Details</span>
        </div>
      }
      canOutsideClickClose={false}
      canEscapeKeyClose={true}
      hasBackdrop={false}
      position="right"
      portalClassName="task-details-portal"
      className="task-details-drawer"
    >
      {taskData && (
        <div className={Classes.DRAWER_BODY}>
          <div className={Classes.DIALOG_BODY} style={{ padding: 20 }}>
            {/* Task Type Header */}
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 12,
                marginBottom: 16,
              }}
            >
              <Icon icon={getTypeIcon(taskData.type)} size={24} />
              <div>
                <H4 style={{ margin: 0 }}>{capitalize(taskData.type)}</H4>
                <Tag
                  intent={getTypeIntent(taskData.type)}
                  minimal
                  style={{ marginTop: 4 }}
                >
                  {taskData.type.toUpperCase()}
                </Tag>
              </div>
              {taskData.hasConflict && (
                <Tag intent={Intent.DANGER} icon="warning-sign" large>
                  CONFLICT
                </Tag>
              )}
            </div>

            <Divider />

            {/* Train Information */}
            <div style={{ marginTop: 16 }}>
              <H5 style={{ marginBottom: 12, color: '#5c7080' }}>
                <Icon icon="train" style={{ marginRight: 8 }} />
                Train Information
              </H5>
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: '100px 1fr',
                  gap: '8px 12px',
                  fontSize: 14,
                }}
              >
                <span style={{ color: '#5c7080' }}>Train ID:</span>
                <span style={{ fontFamily: 'monospace', fontWeight: 600 }}>
                  {taskData.trainId}
                </span>

                <span style={{ color: '#5c7080' }}>Fleet:</span>
                <span style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <Icon icon={getAssetIcon(taskData.assetType)} size={14} />
                  {taskData.assetType}
                </span>
              </div>
            </div>

            <Divider style={{ margin: '16px 0' }} />

            {/* Schedule Information */}
            <div>
              <H5 style={{ marginBottom: 12, color: '#5c7080' }}>
                <Icon icon="calendar" style={{ marginRight: 8 }} />
                Schedule
              </H5>
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: '100px 1fr',
                  gap: '8px 12px',
                  fontSize: 14,
                }}
              >
                <span style={{ color: '#5c7080' }}>Start Date:</span>
                <span>{formatDate(taskData.startDate)}</span>

                <span style={{ color: '#5c7080' }}>End Date:</span>
                <span>{formatDate(taskData.endDate)}</span>

                <span style={{ color: '#5c7080' }}>Duration:</span>
                <span style={{ fontWeight: 600 }}>
                  {taskData.duration} day{taskData.duration !== 1 ? 's' : ''}
                </span>
              </div>
            </div>

            <Divider style={{ margin: '16px 0' }} />

            {/* Status */}
            <div>
              <H5 style={{ marginBottom: 12, color: '#5c7080' }}>
                <Icon icon="tick-circle" style={{ marginRight: 8 }} />
                Status
              </H5>
              <div
                style={{
                  display: 'flex',
                  flexWrap: 'wrap',
                  gap: 8,
                }}
              >
                <Tag
                  intent={taskData.hasConflict ? Intent.DANGER : Intent.SUCCESS}
                  icon={taskData.hasConflict ? 'warning-sign' : 'tick'}
                >
                  {taskData.hasConflict
                    ? 'Has Scheduling Conflict'
                    : 'No Conflicts'}
                </Tag>
                <Tag intent={Intent.NONE} icon="time" minimal>
                  Scheduled
                </Tag>
              </div>
            </div>

            {/* Dependencies (if any) */}
            {(taskData.predecessorId || taskData.successorTasks.length > 0) && (
              <>
                <Divider style={{ margin: '16px 0' }} />
                <div>
                  <H5 style={{ marginBottom: 12, color: '#5c7080' }}>
                    <Icon icon="link" style={{ marginRight: 8 }} />
                    Dependencies
                  </H5>

                  {taskData.predecessorTask && (
                    <div style={{ marginBottom: 8 }}>
                      <span
                        style={{
                          fontSize: 12,
                          color: '#5c7080',
                          display: 'block',
                          marginBottom: 4,
                        }}
                      >
                        Depends on:
                      </span>
                      <Tag
                        icon={getTypeIcon(taskData.predecessorTask.type)}
                        intent={getTypeIntent(taskData.predecessorTask.type)}
                        minimal
                      >
                        {capitalize(taskData.predecessorTask.type)} (
                        {taskData.predecessorTask.trainId})
                      </Tag>
                    </div>
                  )}

                  {taskData.successorTasks.length > 0 && (
                    <div>
                      <span
                        style={{
                          fontSize: 12,
                          color: '#5c7080',
                          display: 'block',
                          marginBottom: 4,
                        }}
                      >
                        Required by:
                      </span>
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                        {taskData.successorTasks.map((t) => (
                          <Tag
                            key={t.id}
                            icon={getTypeIcon(t.type)}
                            intent={getTypeIntent(t.type)}
                            minimal
                          >
                            {capitalize(t.type)} ({t.trainId})
                          </Tag>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </>
            )}

            {/* Technical Info (collapsed by default) */}
            <Divider style={{ margin: '16px 0' }} />
            <div>
              <H5 style={{ marginBottom: 12, color: '#5c7080' }}>
                <Icon icon="code" style={{ marginRight: 8 }} />
                Technical Info
              </H5>
              <div
                style={{
                  backgroundColor: '#f5f8fa',
                  padding: 12,
                  borderRadius: 4,
                  fontSize: 12,
                  fontFamily: 'monospace',
                }}
              >
                <div>Task ID: {taskData.id}</div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer with close button */}
      <div className={Classes.DRAWER_FOOTER} style={{ padding: 16 }}>
        <Button intent={Intent.PRIMARY} onClick={handleClose} fill>
          Close
        </Button>
      </div>
    </Drawer>
  );
}

