     1→/**
     2→ * TimelineHeader - Displays date labels synced with canvas panX
     3→ *
     4→ * Features:
     5→ * - Adaptive granularity based on zoom level:
     6→ *   - Low zoom (< 0.5): Years
     7→ *   - Medium zoom (0.5-1.5): Months
     8→ *   - High zoom (1.5-3.0): Weeks
     9→ *   - Very high zoom (> 3.0): Days
    10→ * - Labels positioned to align with canvas content
    11→ * - Labels don't overlap (spacing adjusted based on zoom)
    12→ *
    13→ * D3-MIGRATE-001: Uses d3-time and d3-time-format for date operations
    14→ */
    15→
    16→import { useMemo } from 'react';
    17→import { timeYear, timeMonth, timeWeek, timeDay } from 'd3-time';
    18→import { timeFormat } from 'd3-time-format';
    19→import { DEFAULT_VIEW_CONFIG, DEFAULT_DATASET_META } from '../data/types';
    20→
    21→interface TimelineHeaderProps {
    22→  /** Left edge of the visible viewport in world X coordinates */
    23→  viewportLeftX: number;
    24→  /** Right edge of the visible viewport in world X coordinates */
    25→  viewportRightX: number;
    26→  /** Current zoom level */
    27→  zoom: number;
    28→  /** Width of the sidebar (to offset the timeline) */
    29→  sidebarWidth: number;
    30→  /** Callback when a date label is clicked (F124: navigation) */
    31→  onDateClick?: (dayOffset: number) => void;
    32→}
    33→
    34→const { pxPerDay } = DEFAULT_VIEW_CONFIG;
    35→const START_DATE = new Date(DEFAULT_DATASET_META.startDate);
    36→
    37→// D3-MIGRATE-001: Format helpers using d3-time-format
    38→const formatYear = timeFormat('%Y');
    39→const formatMonth = timeFormat('%b %Y');
    40→const formatWeek = timeFormat('%b %d');
    41→const formatDay = timeFormat('%a, %b %d');
    42→
    43→/**
    44→ * Calculate the appropriate granularity based on zoom level
    45→ */
    46→type Granularity = 'year' | 'month' | 'week' | 'day';
    47→
    48→function getGranularity(zoom: number): Granularity {
    49→  if (zoom < 0.5) return 'year';
    50→  if (zoom < 1.5) return 'month';
    51→  if (zoom < 3.0) return 'week';
    52→  return 'day';
    53→}
    54→
    55→/**
    56→ * Get the minimum pixel spacing between labels for each granularity
    57→ */
    58→function getMinLabelSpacing(granularity: Granularity): number {
    59→  switch (granularity) {
    60→    case 'year':
    61→      return 80;
    62→    case 'month':
    63→      return 70;
    64→    case 'week':
    65→      return 60;
