    23→import { useRef, useMemo, useEffect, useState } from 'react';
    24→import { EntityStore, getEntityStore } from './EntityStore';
    25→import type { TaskData, TaskCursor } from './types';
    26→import type { TaskRender } from '../data/types';
    27→import { TASK_TYPE_TO_VALUE, TASK_COLOR_TO_VALUE } from './types';
    28→
    29→/**
    30→ * Convert TaskRender to TaskData format for EntityStore
    31→ */
