    54→  taskCount: number;
    55→  /** Get a task cursor by ID (returns new cursor, safe to store) */
    56→  getTask: (id: string) => TaskCursor | null;
    57→  /** Get a task cursor by index (returns new cursor, safe to store) */
    58→  getTaskByIndex: (index: number) => TaskCursor | null;
    59→  /** Iterate over all tasks (yields fresh cursors) */
    60→  iterateTasks: () => IterableIterator<TaskCursor>;
    61→}
    62→
    63→/**
    64→ * Hook that manages EntityStore lifecycle and provides access to entity data.
    65→ *
    66→ * @param tasks - Array of TaskRender objects from the generator
    67→ * @returns EntityStore access interface
    68→ */
    69→export function useEntityStore(tasks: TaskRender[]): UseEntityStoreResult {
    70→  const storeRef = useRef<EntityStore | null>(null);
    71→  const [isLoaded, setIsLoaded] = useState(false);
    72→
