     1→     1→/**
     2→     2→ * Mock Data Generator
     3→     3→ *
     4→     4→ * Generates test data for the MMS visualization:
     5→     5→ * - 50 trains (30 ALSTOM + 20 KINKI)
     6→     6→ * - 10 years of tasks per train
     7→     7→ * - ~10-12 tasks per train per year
     8→     8→ * - ~5% of tasks have conflict flags
     9→     9→ */
    10→    10→
    11→    11→import type {
    12→    12→  Train,
    13→    13→  Task,
    14→    14→  TaskRender,
    15→    15→  GeneratedData,
    16→    16→  DatasetMeta,
    17→    17→  TaskType,
    18→    18→  AssetType,
    19→    19→} from './types';
    20→    20→import { TYPE_TO_COLOR, DEFAULT_DATASET_META } from './types';
    21→    21→
    22→    22→// ─────────────────────────────────────────────────────────────
    23→    23→// DATE HELPERS
    24→    24→// ─────────────────────────────────────────────────────────────
    25→    25→
    26→    26→/**
    27→    27→ * Format date as ISO 8601 string (YYYY-MM-DD)
    28→    28→ */
    29→    29→function formatISO(date: Date): string {
    30→    30→  return date.toISOString().split('T')[0];
    31→    31→}
    32→    32→
    33→    33→/**
    34→    34→ * Add days to a date
    35→    35→ */
    36→    36→function addDays(date: Date | string, days: number): Date {
    37→    37→  const d = typeof date === 'string' ? new Date(date) : new Date(date);
    38→    38→  d.setDate(d.getDate() + days);
    39→    39→  return d;
    40→    40→}
    41→    41→
    42→    42→/**
    43→    43→ * Calculate days between two dates
    44→    44→ */
    45→    45→function daysBetween(start: Date | string, end: Date | string): number {
    46→    46→  const s = typeof start === 'string' ? new Date(start) : start;
    47→    47→  const e = typeof end === 'string' ? new Date(end) : end;
    48→    48→  const diffTime = e.getTime() - s.getTime();
    49→    49→  return Math.floor(diffTime / (1000 * 60 * 60 * 24));
    50→    50→}
    51→    51→
    52→    52→// ─────────────────────────────────────────────────────────────
    53→    53→// DATA GENERATION
    54→    54→// ─────────────────────────────────────────────────────────────
    55→    55→
    56→    56→/**
    57→    57→ * Generate train entities
    58→    58→ */
    59→    59→function generateTrains(count: number): Train[] {
    60→    60→  return Array.from({ length: count }, (_, i) => {
    61→    61→    const isAlstom = i < Math.floor(count * 0.6); // 60% Alstom
    62→    62→    return {
    63→    63→      id: `TRAIN-${String(i + 1).padStart(3, '0')}`,
    64→    64→      name: `Train ${i + 1}`,
    65→    65→      assetType: (isAlstom ? 'ALSTOM' : 'KINKI') as AssetType,
    66→    66→    };
    67→    67→  });
    68→    68→}
    69→    69→
    70→    70→/**
    71→    71→ * Generate tasks for all trains
    72→    72→ */
    73→    73→function generateTasks(trains: Train[], meta: DatasetMeta): Task[] {
    74→    74→  const tasks: Task[] = [];
    75→    75→  const types: TaskType[] = ['maintenance', 'overhaul', 'inspection'];
    76→    76→
    77→    77→  trains.forEach((train, trainIndex) => {
    78→    78→    for (let year = 0; year < meta.years; year++) {
    79→    79→      // 8-12 tasks per year per train
    80→    80→      const tasksPerYear = 8 + Math.floor(Math.random() * 5);
    81→    81→
    82→    82→      for (let t = 0; t < tasksPerYear; t++) {
    83→    83→        // First task of year 0 for each train starts early (within first 60 days)
    84→    84→        // This ensures data is visible at initial camera position
    85→    85→        let dayOffset: number;
    86→    86→        if (year === 0 && t === 0) {
    87→    87→          dayOffset = trainIndex * 3 + Math.floor(Math.random() * 30);
    88→    88→        } else {
    89→    89→          dayOffset = year * 365 + Math.floor(Math.random() * 360);
    90→    90→        }
    91→    91→        const duration = 2 + Math.floor(Math.random() * 10);
    92→    92→        const startDate = addDays(meta.startDate, dayOffset);
    93→    93→        const endDate = addDays(startDate, duration);
    94→    94→
    95→    95→        tasks.push({
    96→    96→          id: `${train.id}-${year}-${t}`,
    97→    97→          trainId: train.id,
    98→    98→          startDate: formatISO(startDate),
    99→    99→          endDate: formatISO(endDate),
   100→   100→          type: types[Math.floor(Math.random() * types.length)],
   101→   101→          hasConflict: Math.random() < 0.05, // 5% conflict rate
   102→   102→        });
   103→   103→      }
   104→   104→    }
   105→   105→  });
   106→   106→
   107→   107→  // Add dependencies between tasks (F023)
   108→   108→  // ~10-15% of tasks will have a predecessor
   109→   109→  // Dependencies can be within the same train or across different trains
   110→   110→  addDependencies(tasks, meta);
   111→   111→
   112→   112→  return tasks;
   113→   113→}
   114→   114→
   115→   115→/**
   116→   116→ * Add dependency relationships between tasks (F023)
   117→   117→ *
   118→   118→ * Strategy:
   119→   119→ * - ~10-15% of tasks get a predecessor
   120→   120→ * - Predecessor must end before the current task starts (valid dependency)
   121→   121→ * - Mix of same-train and cross-train dependencies
   122→   122→ * - Overhauls often depend on inspections (realistic pattern)
   123→   123→ */
   124→   124→function addDependencies(tasks: Task[], meta: DatasetMeta): void {
   125→   125→  // Build a lookup by start date for efficient predecessor search
   126→   126→  const sortedTasks = [...tasks].sort(
   127→   127→    (a, b) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime()
   128→   128→  );
   129→   129→
   130→   130→  // Create a map for quick task lookup
   131→   131→  const taskMap = new Map<string, Task>(tasks.map((t) => [t.id, t]));
   132→   132→
   133→   133→  // Group tasks by train for same-train dependencies
   134→   134→  const tasksByTrain = new Map<string, Task[]>();
   135→   135→  for (const task of sortedTasks) {
   136→   136→    const list = tasksByTrain.get(task.trainId) || [];
   137→   137→    list.push(task);
   138→   138→    tasksByTrain.set(task.trainId, list);
   139→   139→  }
