   146→   146→    // ~12% chance of having a dependency
   147→   147→    if (Math.random() >= 0.12) continue;
   148→   148→
   149→   149→    const taskStartTime = new Date(task.startDate).getTime();
   150→   150→
   151→   151→    // 70% same-train dependency, 30% cross-train dependency
   152→   152→    const sameTrain = Math.random() < 0.7;
   153→   153→
   154→   154→    let candidates: Task[];
   155→   155→    if (sameTrain) {
   156→   156→      // Find tasks on the same train that end before this one starts
   157→   157→      candidates = (tasksByTrain.get(task.trainId) || []).filter((t) => {
   158→   158→        const endTime = new Date(t.endDate).getTime();
   159→   159→        // Predecessor must end at least 1 day before (gap for realism)
   160→   160→        // and within 60 days (reasonable dependency window)
   161→   161→        const gap = (taskStartTime - endTime) / (1000 * 60 * 60 * 24);
   162→   162→        return t.id !== task.id && gap >= 1 && gap <= 60;
   163→   163→      });
   164→   164→    } else {
   165→   165→      // Find tasks on different trains that end before this one starts
   166→   166→      candidates = sortedTasks.filter((t) => {
   167→   167→        if (t.trainId === task.trainId || t.id === task.id) return false;
   168→   168→        const endTime = new Date(t.endDate).getTime();
   169→   169→        const gap = (taskStartTime - endTime) / (1000 * 60 * 60 * 24);
   170→   170→        return gap >= 1 && gap <= 30; // Tighter window for cross-train
   171→   171→      });
   172→   172→    }
   173→   173→
   174→   174→    if (candidates.length > 0) {
   175→   175→      // Pick a random predecessor from candidates
   176→   176→      const predecessor = candidates[Math.floor(Math.random() * candidates.length)];
   177→   177→      task.predecessorId = predecessor.id;
   178→   178→    }
   179→   179→  }
