   181→   181→
   182→   182→/**
   183→   183→ * Generate complete dataset
   184→   184→ */
   185→   185→export function generateData(meta: DatasetMeta = DEFAULT_DATASET_META): GeneratedData {
   186→   186→  const trains = generateTrains(meta.trainCount);
