export function InfiniteCanvas({
  zoom,
  lod,
  onZoomChange,
  onViewportChange,
  onMinZoomChange,
  animatedZoomTarget,
  onAnimatedZoomComplete,
  navigationTarget,
  onNavigationComplete,
  perfVisible = false,
  perfEvent = 'idle',
